package store

import (
	"context"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/valkey-io/valkey-go"
)

var (
	ErrNotFound = errors.New("store: not found")
)

const (
	SessionKeyPrefix    = "session:"
	SessionExpiryKey    = "session:expiry"
	SessionLastActivity = "session:last_activity"
)

type Store interface {
	Ping(ctx context.Context) error
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)
	StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error
	UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error)
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error)
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error
	Close() error
}

type SandboxInfo struct {
	SessionID   string      `json:"session_id"`
	SandboxID   string      `json:"sandbox_id"`
	SandboxName string      `json:"sandbox_name"`
	Namespace   string      `json:"namespace"`
	Kind        string      `json:"kind"`
	EntryPoints []EntryPoint `json:"entry_points"`
	CreatedAt   time.Time   `json:"created_at"`
	ExpiresAt   time.Time   `json:"expires_at"`
}

type EntryPoint struct {
	Path      string `json:"path"`
	Protocol  string `json:"protocol"`
	Endpoint  string `json:"endpoint"`
}

var (
	storage     Store
	storageOnce sync.Once
	storageErr  error
)

func Storage() Store {
	storageOnce.Do(func() {
		storage, storageErr = newStore()
	})
	if storageErr != nil {
		panic(fmt.Sprintf("failed to initialize store: %v", storageErr))
	}
	return storage
}

func newStore() (Store, error) {
	storeType := getEnv("STORE_TYPE", "redis")

	switch strings.ToLower(storeType) {
	case "redis":
		return newRedisStore()
	case "valkey":
		return newValkeyStore()
	default:
		return nil, fmt.Errorf("unsupported store type: %s", storeType)
	}
}

func getEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

func newRedisStore() (Store, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, fmt.Errorf("REDIS_ADDR is required")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("REDIS_PASSWORD_REQUIRED"); val != "" {
		if parsed, err := strconv.ParseBool(val); err == nil {
			passwordRequired = parsed
		}
	}
	if passwordRequired && password == "" {
		return nil, fmt.Errorf("REDIS_PASSWORD is required")
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &redisStore{client: client}, nil
}

func newValkeyStore() (Store, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, fmt.Errorf("VALKEY_ADDR is required")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("VALKEY_PASSWORD_REQUIRED"); val != "" {
		if parsed, err := strconv.ParseBool(val); err == nil {
			passwordRequired = parsed
		}
	}
	if passwordRequired && password == "" {
		return nil, fmt.Errorf("VALKEY_PASSWORD is required")
	}

	addresses := strings.Split(addr, ",")

	disableCache := false
	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		if parsed, err := strconv.ParseBool(val); err == nil {
			disableCache = parsed
		}
	}

	forceSingle := false
	if val := valkeyEnv("VALKEY_FORCE_SINGLE"); val != "" {
		if parsed, err := strconv.ParseBool(val); err == nil {
			forceSingle = parsed
		}
	}

	clusterMode := valkeyGoClusterMode{
		InitAddress:         addresses,
		DisableCache:       disableCache,
		ForceSingleClient:   forceSingle,
		Password:           password,
	}

	return &valkeyStore{client: clusterMode}, nil
}

func valkeyEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

type valkeyGoClusterMode struct {
	InitAddress       []string
	DisableCache       bool
	ForceSingleClient  bool
	Password          string
}

type redisStore struct {
	client *redis.Client
}

func (r *redisStore) Ping(ctx context.Context) error {
	result, err := r.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected PING response: %s", result)
	}
	return nil
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := SessionKeyPrefix + sessionID
	data, err := r.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}
	return &sandbox, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("ExpiresAt is required")
	}

	key := SessionKeyPrefix + sandbox.SessionID

	pipe := r.client.Pipeline()

	existsCmd := pipe.Exists(ctx, key)
	_, err := pipe.Exec(ctx)
	if err != nil {
		return err
	}
	if existsCmd.Val() > 0 {
		return fmt.Errorf("session already exists")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	now := time.Now().Unix()
	expiryScore := float64(sandbox.ExpiresAt.Unix())

	cmds, err := r.client.TxPipelined(ctx, func(pipe redis.Pipeliner) error {
		pipe.SetNX(ctx, key, data, 0)
		pipe.ZAdd(ctx, SessionExpiryKey, redis.Z{Score: expiryScore, Member: sandbox.SessionID})
		pipe.ZAdd(ctx, SessionLastActivity, redis.Z{Score: float64(now), Member: sandbox.SessionID})
		return nil
	})
	if err != nil {
		return err
	}

	for _, cmd := range cmds {
		if cmd.Err() != nil {
			return cmd.Err()
		}
	}

	return nil
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox is nil")
	}

	key := SessionKeyPrefix + sandbox.SessionID

	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return fmt.Errorf("key not exists")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	err = r.client.Set(ctx, key, data, 0).Err()
	if err != nil {
		return err
	}

	return nil
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := SessionKeyPrefix + sessionID

	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, SessionExpiryKey, sessionID)
	pipe.ZRem(ctx, SessionLastActivity, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	members, err := r.client.ZRangeByScore(ctx, SessionExpiryKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, members)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	members, err := r.client.ZRangeByScore(ctx, SessionLastActivity, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, members)
}

func (r *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = SessionKeyPrefix + id
	}

	results, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	var sandboxes []*SandboxInfo
	for i, result := range results {
		if result == nil {
			continue
		}
		var sandbox SandboxInfo
		if err := json.Unmarshal([]byte(result.(string)), &sandbox); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session id is required")
	}

	key := SessionKeyPrefix + sessionID

	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	timestamp := at.Unix()
	if at.IsZero() {
		timestamp = time.Now().Unix()
	}

	err = r.client.ZAdd(ctx, SessionLastActivity, redis.Z{
		Score:  float64(timestamp),
		Member: sessionID,
	}).Err()
	if err != nil {
		return err
	}

	return nil
}

func (r *redisStore) Close() error {
	return r.client.Close()
}

