	ErrAgentRuntimeNotFound   = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing        = errors.New("template missing")
	ErrPublicKeyMissing       = errors.New("public key missing")
)

type APIStatus interface {
	Status() string
	Message() string
	Reason() string
	Group() string
	Kind() string
	Name() string
	Code() int
}

type apiStatus struct {
	status  string
	message string
	reason  string
	group   string
	kind    string
	name    string
	code    int
}

func (a *apiStatus) Status() string  { return a.status }
func (a *apiStatus) Message() string { return a.message }
func (a *apiStatus) Reason() string  { return a.reason }
func (a *apiStatus) Group() string   { return a.group }
func (a *apiStatus) Kind() string    { return a.kind }
func (a *apiStatus) Name() string    { return a.name }
func (a *apiStatus) Code() int       { return a.code }

func NewAgentRuntimeNotFoundError(name, namespace string) APIStatus {
	return &apiStatus{
		status:  "Failure",
