type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

func (r *CreateSandboxRequest) Validate() error {
	validKinds := sets.NewString("AgentRuntime", "CodeInterpreter")
	if !validKinds.Has(r.Kind) {
		return fmt.Errorf("kind must be one of AgentRuntime or CodeInterpreter")
	}
	if r.Namespace == "" {
		return fmt.Errorf("namespace is required")
	}
	if r.Name == "" {
		return fmt.Errorf("name is required")
	}
	return nil
}

type CreateSandboxResponse struct {
	SessionID   string       `json:"sessionId"`
	SandboxID   string       `json:"sandboxId"`
	SandboxName string       `json:"sandboxName"`
	EntryPoints []EntryPoint `json:"entryPoints"`
}

type EntryPoint struct {
	Path      string `json:"path"`
	Protocol  string `json:"protocol"`
	Endpoint  string `json:"endpoint"`
}

type ErrorResponse struct {
	Message string `json:"message"`
}

type SuccessResponse struct {
	Message string `json:"message"`
}

type HealthResponse struct {
	Status string `json:"status"`
}

func (h *HealthResponse) JSON() string {
	data, _ := json.Marshal(h)
	return string(data)
}

func NewHealthResponse(status string) *HealthResponse {
	return &HealthResponse{Status: status}
}

func NewErrorResponse(message string) *ErrorResponse {
	return &ErrorResponse{Message: message}
}

func NewSuccessResponse(message string) *SuccessResponse {
	return &SuccessResponse{Message: message}
}

