)

var (
	listen       string
	certFile     string
	keyFile      string
	enableAuth   bool
	enableTLS    bool
	redisAddr    string
	redisPass    string
)

const (
	DefaultSessionTimeout       = 15 * time.Minute
	DefaultMaxSessionDuration  = 8 * time.Hour
	DefaultSandboxIdleTimeout  = 15 * time.Minute
	SessionStoreKeyPrefix      = "session:"
	SessionExpiryKey          = "session:expiry"
	SessionLastActivity       = "session:last_activity"
)

type UserInfo struct {
	Token            string
	Username         string
	ServiceAccount  string
	Namespace       string
}

type Server struct {
	engine          *gin.Engine
	store           store.Store
	arInformer      cache.ListerGetter
	ciInformer      cache.ListerGetter
	podInformer     cache.ListerGetter
	enableAuth      bool
	enableTLS       bool
	certFile        string
	keyFile         string
	userClients     map[string]*dynamic.Client
	clientLock      sync.RWMutex
	shutdownCh      chan struct{}
	wg              sync.WaitGroup
}

func main() {
	klog.InitFlags(nil)
	flag.StringVar(&listen, "listen", ":8080", "Listen address")
	flag.StringVar(&certFile, "cert", "", "TLS certificate file")
	flag.StringVar(&keyFile, "key", "", "TLS key file")
	flag.BoolVar(&enableTLS, "enable-tls", false, "Enable TLS")
	flag.BoolVar(&enableAuth, "enable-auth", false, "Enable authentication")
	flag.StringVar(&redisAddr, "redis-addr", os.Getenv("REDIS_ADDR"), "Redis address")
	flag.StringVar(&redisPass, "redis-password", os.Getenv("REDIS_PASSWORD"), "Redis password")
	flag.Parse()

	if enableTLS && (certFile == "" || keyFile == "") {
		klog.Exitf("TLS is enabled but cert or key not provided")
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	storeInst := store.Storage()
	if err := storeInst.Ping(ctx); err != nil {
		klog.Exitf("Failed to ping store: %v", err)
	}
	klog.Info("Store connection verified")

	srv := &Server{
		engine:      gin.New(),
		store:       storeInst,
		enableAuth:  enableAuth,
		enableTLS:   enableTLS,
		certFile:    certFile,
		keyFile:    keyFile,
		userClients: make(map[string]*dynamic.Client),
		shutdownCh:  make(chan struct{}),
	}

	srv.setupRoutes()
	srv.startGC(ctx)

	go func() {
		if err := srv.start(); err != nil && err != http.ErrServerClosed {
			klog.Exitf("Server error: %v", err)
		}
	}()

	klog.Infof("Workload manager listening on %s", listen)

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit
	klog.Info("Shutting down server...")

	cancel()

	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer shutdownCancel()

	srv.shutdown(shutdownCtx)
	storeInst.Close()
	klog.Info("Server stopped")
}

