func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, api.NewHealthResponse("healthy"))
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()
		klog.V(4).Infof("[%d] %s %s - %v", status, c.Request.Method, path, latency)
	}
}

func authMiddleware(srv *Server) gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, api.NewErrorResponse("Missing authorization header"))
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, api.NewErrorResponse("Invalid authorization header format"))
			return
		}

		token := parts[1]
		userInfo, err := validateServiceAccountToken(token)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusUnauthorized, api.NewErrorResponse(fmt.Sprintf("Invalid token: %v", err)))
			return
		}

		c.Set("user", userInfo)
		c.Next()
	}
}

func validateServiceAccountToken(token string) (*UserInfo, error) {
	return &UserInfo{
		Token:        token,
		Username:     "system:serviceaccount:default:default",
		ServiceAccount: "default",
		Namespace:   "default",
	}, nil
}

