	if err := s.store.DeleteSandboxBySessionID(c.Request.Context(), sessionID); err != nil {
		c.JSON(http.StatusInternalServerError, api.NewErrorResponse(err.Error()))
		return
	}

	c.JSON(http.StatusOK, api.NewSuccessResponse("Sandbox deleted successfully"))
}

func handleError(c *gin.Context, err error) {
	if apiStatus, ok := err.(api.APIStatus); ok {
		c.JSON(apiStatus.Code(), api.NewErrorResponse(apiStatus.Message()))
		return
	}
	c.JSON(http.StatusInternalServerError, api.NewErrorResponse("internal server error"))
}

func (s *Server) startGC(ctx context.Context) {
	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		ticker := time.NewTicker(15 * time.Second)
		defer ticker.Stop()

		for {
			select {
			case <-ctx.Done():
				return
			case <-ticker.C:
				s.runGC(ctx)
			}
		}
	}()
}

func (s *Server) runGC(ctx context.Context) {
	gcCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	now := time.Now()
	inactiveCutoff := now.Add(-DefaultSandboxIdleTimeout)

	batchLimit := 16
	expired, err := s.store.ListExpiredSandboxes(gcCtx, now, batchLimit)
	if err != nil {
		klog.Errorf("Failed to list expired sandboxes: %v", err)
		return
	}

	inactive, err := s.store.ListInactiveSandboxes(gcCtx, inactiveCutoff, batchLimit)
	if err != nil {
		klog.Errorf("Failed to list inactive sandboxes: %v", err)
		return
	}

	seen := make(map[string]bool)
	for _, sb := range append(expired, inactive...) {
		if seen[sb.SessionID] {
			continue
		}
		seen[sb.SessionID] = true

		if err := s.store.DeleteSandboxBySessionID(gcCtx, sb.SessionID); err != nil {
			klog.Errorf("Failed to delete sandbox %s: %v", sb.SessionID, err)
		}
	}
}

func (s *Server) start() error {
	server := &http.Server{
		Addr:         listen,
		Handler:      s.engine,
		ReadTimeout:  15 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	if s.enableTLS {
		return server.ListenAndServeTLS(s.certFile, s.keyFile)
	}

	return server.ListenAndServe()
}

func (s *Server) shutdown(ctx context.Context) {
	close(s.shutdownCh)
	s.wg.Wait()
}

func generateSessionID() string {
	return fmt.Sprintf("sess-%d-%s", time.Now().UnixNano(), randomString(8))
}

func generateSandboxID() string {
	return fmt.Sprintf("sbx-%d-%s", time.Now().UnixNano(), randomString(8))
}

func randomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[time.Now().UnixNano()%int64(len(letters))]
		time.Sleep(time.Nanosecond)
	}
	return string(b)
}

import os
from pathlib import Path
from typing import Optional, Dict, Any
import yaml


class AgentMetadata:
    def __init__(
        self,
        agent_name: Optional[str] = None,
        language: Optional[str] = None,
        build_mode: Optional[str] = None,
        entrypoint: Optional[str] = None,
        port: Optional[int] = None,
        version: str = "0.0.1",
        description: Optional[str] = None,
        workspace_path: Optional[str] = None,
    ):
        self.agent_name = agent_name
        self.language = language
        self.build_mode = build_mode
        self.entrypoint = entrypoint
        self.port = port
        self.version = version
        self.description = description
        self.workspace_path = workspace_path
        self._data: Dict[str, Any] = {}

    def validate(self) -> bool:
        if self.language and self.language not in ["python", "java", "go", "node"]:
            raise ValueError(f"Unsupported language: {self.language}")

        if self.build_mode and self.build_mode not in ["local", "cloud"]:
            raise ValueError(f"Unsupported build_mode: {self.build_mode}")

        if self.port and (self.port < 1 or self.port > 65535):
            raise ValueError(f"Invalid port: {self.port}")

        return True

    def to_dict(self) -> Dict[str, Any]:
        result = {}
        if self.agent_name:
            result["agent_name"] = self.agent_name
        if self.language:
            result["language"] = self.language
        if self.build_mode:
            result["build_mode"] = self.build_mode
        if self.entrypoint:
            result["entrypoint"] = self.entrypoint
        if self.port:
            result["port"] = self.port
        result["version"] = self.version
        if self.description:
            result["description"] = self.description
        if self.workspace_path:
            result["workspace_path"] = self.workspace_path
        return result

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "AgentMetadata":
        metadata = cls(
            agent_name=data.get("agent_name"),
            language=data.get("language"),
            build_mode=data.get("build_mode"),
            entrypoint=data.get("entrypoint"),
            port=data.get("port"),
            version=data.get("version", "0.0.1"),
            description=data.get("description"),
            workspace_path=data.get("workspace_path"),
        )
        metadata._data = data
        return metadata


class MetadataService:
    @staticmethod
    def save_metadata(workspace: str, metadata: AgentMetadata) -> str:
        metadata_path = os.path.join(workspace, "agent_metadata.yaml")
        with open(metadata_path, "w") as f:
            yaml.dump(
                metadata.to_dict(),
                f,
                default_flow_style=False,
                indent=2,
                sort_keys=False,
            )
        return metadata_path

    @staticmethod
    def load_metadata(workspace: str) -> Optional[AgentMetadata]:
        for filename in ["agent_metadata.yaml", "agent.yaml", "metadata.yaml"]:
            path = os.path.join(workspace, filename)
            if os.path.exists(path):
                with open(path, "r") as f:
                    data = yaml.safe_load(f)
                    if data:
                        return AgentMetadata.from_dict(data)
        return None


class PackRuntime:
    def __init__(
        self,
        workspace: str = ".",
        agent_name: Optional[str] = None,
        language: Optional[str] = None,
        entrypoint: Optional[str] = None,
        port: Optional[int] = None,
        build_mode: Optional[str] = None,
        description: Optional[str] = None,
        output: Optional[str] = None,
    ):
        self.workspace = workspace
        self.agent_name = agent_name
        self.language = language
        self.entrypoint = entrypoint
        self.port = port
        self.build_mode = build_mode
        self.description = description
        self.output = output

    def _validate_workspace_structure(self) -> None:
        workspace_path = Path(self.workspace)

        if not workspace_path.exists():
            raise ValueError(f"Workspace directory does not exist: {self.workspace}")

        if not workspace_path.is_dir():
            raise ValueError(f"Workspace is not a directory: {self.workspace}")

        if self.language == "python":
            py_files = list(workspace_path.glob("*.py"))
            if not py_files:
                raise ValueError("No Python files found in workspace")

        elif self.language == "java":
            pom_file = workspace_path / "pom.xml"
            if not pom_file.exists():
                raise ValueError("No pom.xml found in workspace")

    def pack(self) -> Dict[str, Any]:
        self._validate_workspace_structure()

        metadata = MetadataService.load_metadata(self.workspace)
        if not metadata:
            metadata = AgentMetadata()

        if self.agent_name:
            metadata.agent_name = self.agent_name
        if self.language:
            metadata.language = self.language
        if self.entrypoint:
            metadata.entrypoint = self.entrypoint
        if self.port:
            metadata.port = self.port
        if self.build_mode:
            metadata.build_mode = self.build_mode
        if self.description:
            metadata.description = self.description

        metadata.workspace_path = os.path.abspath(self.workspace)

        metadata.validate()

        metadata_path = MetadataService.save_metadata(self.workspace, metadata)

        return {
            "agent_name": metadata.agent_name,
            "workspace_path": metadata_path.replace("agent_metadata.yaml", ""),
            "metadata_path": metadata_path,
        }

import os
