        buildargs: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        client = docker.from_env()

        try:
            image, logs = client.images.build(
                path=workspace,
                tag=f"{image_name}:{tag}",
                buildargs=buildargs or {},
                rm=True,
            )

            return {
                "image_name": image_name,
                "image_id": image.id,
                "image_size": len(image.attrs.get("RootFS", {}).get("Layers", [])),
                "build_time": image.attrs.get("Created", ""),
            }
        except docker.errors.DockerException as e:
            raise RuntimeError(f"Docker is not available or not running: {e}")

    @staticmethod
    def push_image(
        image_name: str,
        tag: str = "latest",
        registry_url: Optional[str] = None,
        username: Optional[str] = None,
        password: Optional[str] = None,
    ) -> Dict[str, Any]:
        client = docker.from_env()

        full_image = f"{image_name}:{tag}"

        if username and password:
            client.login(username=username, password=password, registry=registry_url or "")

        if registry_url and not image_name.startswith(registry_url):
            new_name = f"{registry_url}/{image_name}"
            client.images.get(full_image).tag(new_name, tag)
            full_image = f"{new_name}:{tag}"

        for log in client.images.push(full_image, stream=True, decode=True):
            pass

        return {
            "pushed_image": full_image,
            "push_time": "",
        }

    @staticmethod
    def remove_image(image_name: str) -> bool:
        try:
            client = docker.from_env()
            client.images.remove(image_name)
            return True
        except Exception:
            return False


class BuildRuntime:
    def __init__(
        self,
        workspace: str = ".",
        proxy: Optional[str] = None,
        cloud_provider: Optional[str] = None,
        output: Optional[str] = None,
    ):
        self.workspace = workspace
        self.proxy = proxy
        self.cloud_provider = cloud_provider
        self.output = output

    def build(self) -> Dict[str, Any]:
        from agentcube.cli.pack import MetadataService, AgentMetadata

        metadata = MetadataService.load_metadata(self.workspace)
        if not metadata:
            raise ValueError("No metadata found. Run 'agentcube pack' first.")

        build_mode = metadata.build_mode or "local"

        if build_mode == "local":
            return self._build_local(metadata)
        else:
            raise ValueError(f"Unsupported build mode: {build_mode}")

    def _build_local(self, metadata: "AgentMetadata") -> Dict[str, Any]:
        from agentcube.services.docker import DockerService

        image_name = metadata.agent_name or "agent"
        current_version = metadata.version

        version_parts = current_version.split(".")
        if len(version_parts) == 3:
            version_parts[2] = str(int(version_parts[2]) + 1)
            new_version = ".".join(version_parts)
        else:
            new_version = f"{current_version}-1"

        try:
            result = DockerService.build_image(
                workspace=self.workspace,
                image_name=image_name,
                tag=new_version,
                buildargs={"http_proxy": self.proxy} if self.proxy else None,
            )

            metadata.version = new_version
            from agentcube.cli.pack import MetadataService
            MetadataService.save_metadata(self.workspace, metadata)

            return result

        except Exception as e:
            metadata.version = current_version
            from agentcube.cli.pack import MetadataService
            MetadataService.save_metadata(self.workspace, metadata)
            raise

import os
from typing import Optional, Dict, Any

import yaml
from kubernetes import client, config
from kubernetes.client.rest import ApiException


class KubernetesProvider:
    def __init__(
        self,
        workspace: str = ".",
        version: Optional[str] = None,
        image_url: Optional[str] = None,
        image_username: Optional[str] = None,
        image_password: Optional[str] = None,
        description: Optional[str] = None,
        region: Optional[str] = None,
        cloud_provider: Optional[str] = None,
        node_port: Optional[int] = None,
        replicas: Optional[int] = None,
        namespace: Optional[str] = None,
    ):
        self.workspace = workspace
        self.version = version
        self.image_url = image_url
        self.image_username = image_username
        self.image_password = image_password
        self.description = description
        self.region = region
        self.cloud_provider = cloud_provider
        self.node_port = node_port
        self.replicas = replicas or 1
        self.namespace = namespace or "default"

    def _get_metadata(self):
        from agentcube.cli.pack import MetadataService
        return MetadataService.load_metadata(self.workspace)

    def deploy_agent(self) -> Dict[str, Any]:
        metadata = self._get_metadata()

        if not metadata:
            raise ValueError("No metadata found. Run 'agentcube pack' first.")

        image = self.image_url or f"{metadata.agent_name}:{self.version or metadata.version}"

        try:
            config.load_kube_config()
        except Exception:
            config.load_incluster_config()

        apps_v1 = client.AppsV1Api()
        core_v1 = client.CoreV1Api()

        deployment_name = f"{metadata.agent_name}-deployment"
        service_name = f"{metadata.agent_name}-service"

        container_port = metadata.port or 8080
        node_port_val = self.node_port or 30000

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=deployment_name, namespace=self.namespace),
            spec=client.V1DeploymentSpec(
                replicas=self.replicas,
                selector=client.V1LabelSelector(
                    match_labels={"app": metadata.agent_name}
                ),
                template=client.V1PodTemplateSpec(
                    metadata=client.V1ObjectMeta(
                        labels={"app": metadata.agent_name}
                    ),
                    spec=client.V1PodSpec(
                        containers=[
                            client.V1Container(
                                name="agent",
                                image=image,
                                ports=[client.V1ContainerPort(container_port=container_port)]
                            )
                        ]
                    )
                )
            )
        )

        try:
            apps_v1.create_namespaced_deployment(
                namespace=self.namespace,
                body=deployment
            )
        except ApiException as e:
            if e.status != 409:
                raise
            apps_v1.replace_namespaced_deployment(
                name=deployment_name,
                namespace=self.namespace,
                body=deployment
            )

        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=service_name, namespace=self.namespace),
            spec=client.V1ServiceSpec(
                type="NodePort",
                selector={"app": metadata.agent_name},
                ports=[client.V1ServicePort(
                    port=container_port,
                    target_port=container_port,
                    node_port=node_port_val
                )]
            )
        )

        try:
            core_v1.create_namespaced_service(
                namespace=self.namespace,
                body=service
            )
        except ApiException as e:
            if e.status != 409:
                raise
            core_v1.replace_namespaced_service(
                name=service_name,
                namespace=self.namespace,
                body=service
            )

        self._wait_for_deployment(deployment_name)

        result = {
            "deployment_name": deployment_name,
            "service_name": service_name,
            "namespace": self.namespace,
            "replicas": self.replicas,
            "container_port": container_port,
            "node_port": node_port_val,
            "service_url": f"http://localhost:{node_port_val}",
            "status": "deployed",
        }

        metadata._data["deployment_info"] = result
        from agentcube.cli.pack import MetadataService
        MetadataService.save_metadata(self.workspace, metadata)

        return result

    def _wait_for_deployment(self, deployment_name: str, timeout: int = 120):
        import time

        try:
            config.load_kube_config()
        except Exception:
            config.load_incluster_config()

        apps_v1 = client.AppsV1Api()

        start_time = time.time()
        while time.time() - start_time < timeout:
            try:
                deployment = apps_v1.read_namespaced_deployment(
                    name=deployment_name,
                    namespace=self.namespace
                )

                ready = deployment.status.ready_replicas or 0
                desired = deployment.spec.replicas or 0

                if ready >= desired:
                    return

            except ApiException:
                pass

            time.sleep(2)

        raise TimeoutError(f"Deployment {deployment_name} not ready within {timeout} seconds")

    def delete_agent(self) -> Dict[str, Any]:
        from agentcube.cli.pack import MetadataService

        metadata = self._get_metadata()
        deployment_info = metadata._data.get("deployment_info", {})

        try:
            config.load_kube_config()
        except Exception:
            config.load_incluster_config()

        apps_v1 = client.AppsV1Api()
        core_v1 = client.CoreV1Api()

        deployment_name = deployment_info.get("deployment_name", f"{metadata.agent_name}-deployment")
        service_name = deployment_info.get("service_name", f"{metadata.agent_name}-service")

        try:
            apps_v1.delete_namespaced_deployment(
                name=deployment_name,
                namespace=self.namespace
            )
        except ApiException as e:
            if e.status != 404:
                pass

        try:
            core_v1.delete_namespaced_service(
                name=service_name,
                namespace=self.namespace
            )
        except ApiException as e:
            if e.status != 404:
                pass

        return {"status": "deleted", "deployment_name": deployment_name, "namespace": self.namespace}


def wait_for_deployment_ready(
    name: str,
    namespace: str = "default",
    timeout: int = 120,
) -> bool:
    import time

    try:
        config.load_kube_config()
    except Exception:
        config.load_incluster_config()

    apps_v1 = client.AppsV1Api()

    start_time = time.time()
    while time.time() - start_time < timeout:
        try:
            deployment = apps_v1.read_namespaced_deployment(
                name=name,
                namespace=namespace
            )

            ready = deployment.status.ready_replicas or 0
            desired = deployment.spec.replicas or 0

            if ready >= desired:
                return True

        except ApiException:
            pass

        time.sleep(2)

    raise TimeoutError(f"Deployment {name} not ready within {timeout} seconds")

